        val embed = buildEmbedWithPlayers(
            player("Meia10",    passAttempts = "40", passesMade = "28"),
            player("Defensor1", passAttempts = "20", passesMade = "14"),
            player("Defensor2", passAttempts = "20", passesMade = "15"),
        ).embeds[0]
